/* 消息容器基础样式 */
body.bubblechat .mes {
    padding: 2px 10px;
    position: relative;
    display: flex;
    align-items: flex-start;
}

/* 用户消息容器方向 */
body.bubblechat .mes[is_user="true"] {
    flex-direction: row-reverse;
}

/* 调整用户消息气泡的位置 */
body.bubblechat .mes[is_user="true"] .mes_block {
    margin-right: -12px; /* 向头像方向移动 */
}

/* 调整系统消息气泡的位置 */
body.bubblechat .mes:not([is_user="true"]) .mes_block {
    margin-left: -10px; /* 向头像方向移动 */
}

/* 基础气泡样式 */
body.bubblechat .mes_block {
    position: relative;
    max-width: 80%;
    width: fit-content;
    min-width: min-content;
    min-height: 40px;
    margin-top: -5px;
    background: transparent;
    transition: all 0.3s ease;
    overflow: visible !important;
}

/* 公共装饰层基础样式 */
body.bubblechat .mes_block::before,
body.bubblechat .mes_block::after {
    content: '';
    position: absolute;
    z-index: 0;
    transition: all 0.3s ease;
}

/* 九宫格装饰层 */
body.bubblechat .mes_block::before {
    inset: 0;  /* 替代 top/right/bottom/left: 0 */
    border-style: solid;
    background: transparent !important;
    pointer-events: none;
    z-index: 1;
}

/* 背景层基础位置 */
body.bubblechat .mes_block::after {
    background-color: #FEFEFE;  /* 默认白色背景 */
    top: 34px;
    right: 31.5px;
    bottom: 21px;
    left: 38.25px;
}

/* 系统消息背景调整 */
body.bubblechat .mes:not([is_user="true"]) .mes_block::after {
    background-color: #FEDEA9;
    top: 34.5px;
    right: 38px;
    bottom: 22.5px;
    left: 31.5px;
}

/* 系统消息(黄狗)装饰 */
body.bubblechat .mes:not([is_user="true"]) .mes_block::before {
    border-width: 35.5px 39px 23.5px 32.5px;
    border-image: url('https://files.catbox.moe/pk4c8u.png') 
                 1420 1560 940 1300 / 35.5px 39px 23.5px 32.5px
                 stretch;
}

/* 用户消息(白猫)装饰 */
body.bubblechat .mes[is_user="true"] .mes_block::before {
    border-width: 35px 32.5px 22.5px 38.75px;
    border-image: url('https://files.catbox.moe/kwcl0r.png')
                 1400 1300 900 1550 / 35px 32.5px 22.5px 38.75px
                 stretch;
}

/* 消息文本样式 */
body.bubblechat .mes_text {
    position: relative;
    z-index: 2;
    padding: 20px 30px 10px 20px;
    width: 100%;
    min-width: 65px;
    min-height: 50px;
    box-sizing: border-box;
    word-break: break-word !important;
    display: block !important;
    overflow: visible !important;
}

/* 消息发送者名称 */
.mes_block .ch_name {
    position: relative;
    z-index: 3;
    max-height: 0;
    max-width: 0;
    overflow: hidden;
    transform: scale(0);
    opacity: 0;
    transform-origin: left center;
    white-space: nowrap;
}

/* 鼠标悬停时显示发送者名称 */
.mes_block:hover .ch_name {
    max-height: none; 
    max-width: 100%;
    transform: scale(1);
    opacity: 1; 
    overflow: visible;
    margin-bottom: -20px;
    transition: transform 0.3s ease, opacity 0.3s ease;  
}

/* 头像容器和基础样式合并 */
.avatar-container,
.mes .avatar {
    position: relative;
    width: 40px;
    height: 40px;
    line-height: 0;
    margin: 0;
    padding: 0;
    display: block;
}

/* 头像图片样式 */
.mes .avatar img {
    width: 40px !important;
    height: 40px !important;
    max-width: 40px !important;
    max-height: 40px !important;
    border: none;
    border-radius: 50%;
    object-fit: cover;
    display: block;
    position: relative;
    z-index: 1;
}

/* 头像装饰的通用样式 */
body.bubblechat .mes .avatar::after {
    content: '';
    position: absolute;
    width: 60px;
    height: 60px;
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 2;
}

/* 系统消息装饰 */
body.bubblechat .mes:not([is_user="true"]) .avatar::after {
    top: -15px;
    left: -10px;
    background-image: url('https://files.catbox.moe/96git6.png');
}

/* 用户消息装饰 */
body.bubblechat .mes[is_user="true"] .avatar::after {
    top: -15px;
    left: -5px;
    background-image: url('https://files.catbox.moe/upsb8b.png');
}

/* 去除顶部栏的阴影效果 */
* {
    box-shadow: none !important;
}

/* 破限栏条目颜色 */
* {
    --white30a: rgba(184, 155, 122, 0.5);
    --white50a: rgba(184, 155, 122, 0.5);
    --black30a: rgba(255, 246, 230, 0.5);
    --black50a: rgba(255, 246, 230, 0.5);
}

/* 主要按键的颜色 */
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
    background-image: none;
    background-color: #FFF6E6;
    border: 1px solid #B89B7A;
    color: #8B6B4A;
}

/* 菜单按钮和文本框 */
.menu_button, .text_pole, textarea, .edit_textarea {
    background-color: rgba(255, 246, 230, 0.7);
    color: #8B6B4A;
    border: 1px solid #B89B7A;
}

/* 范围滑动条 */
.neo-range-input {
    background-color: rgba(255, 246, 230, 0.8);
    border: 1px solid #B89B7A;
    color: #8B6B4A;
}

.range-block-counter input {
    background-color: rgba(255, 246, 230, 0.8);
    color: #8B6B4A;
    border: 1px solid #B89B7A;
}

/* 下拉选择框 */
select {
    background-color: rgba(255, 246, 230, 0.8);
    color: #8B6B4A;
    border: 1px solid #B89B7A;
}

/* hover效果 */
.menu_button:hover, select:hover {
    background-color: rgba(255, 246, 230, 0.9);
    border-color: #58B9C7;
}

/* 用户消息的文本颜色 */
.mes[is_user="true"] .mes_text {
    color: #A17A7C !important;
}

/* 代码块和小代码块 */
code, pre {
    background-color: rgba(237, 237, 237, 0.5);  /* 透明度改为0.5 */
    border: none;
}

code {
    color: inherit;
}

pre {
    font-family: monospace;
    padding: 10px;
    border-radius: 5px;
    background-clip: padding-box;
    position: relative;
}

/* 禁用 .hljs 的背景颜色和文字颜色 */
.hljs {
    background-color: transparent !important;
    color: inherit !important;
}

/* 为长内容的代码块添加滚动条 */
body.bubblechat .mes_text pre:has(code) {
    max-height: 300px !important;
    overflow-y: auto !important;
}

/* 图片附件的控制按钮样式 */
.mes_img_container .mes_img_controls {
    position: absolute;
    top: 2px;
    z-index: 5;
    display: none;
    padding: 35px;
}

/* 鼠标悬停时显示图片控制按钮 */
.mes_img_container:hover .mes_img_controls {
    display: block;
}

/* 图片附件的显示样式 */
.mes_block img,
.mes_block .attachment,
.mes_block .media {
    position: relative;
    z-index: 3;
    max-width: calc(100% - 70px);
    margin: 20px;
    display: block;
}

/* 底栏QR按键隐藏 */
#send_form:hover #qr--bar {
    height: 40px;
    transition: all 0.5s ease;
}

#qr--bar {
    height: 0.1px;
}

/* 隐藏代理警告 */
#ReverseProxyWarningMessage { display: none !important; }
